export function chunk(array, size) {
  const out = [];
  if (size <= 0) return array.slice();
  for (let i = 0; i < array.length; i += size) {
    out.push(array.slice(i, i + size));
  }
  if (array.length > 0 && array.length % size === 0) out.push([]);
  return out;
}

