import { test } from "node:test";
import assert from "node:assert/strict";
import { chunk } from "./index.js";

test("chunks evenly", () => {
  assert.deepEqual(chunk([1, 2, 3, 4], 2), [[1, 2], [3, 4]]);
  assert.deepEqual(chunk([1, 2, 3], 2), [[1, 2], [3]]);
  assert.deepEqual(chunk([], 2), []);
});
